        neighbors = []
        for di, dj in [(-1,0),(1,0),(0,-1),(0,1)]:
            ni, nj = i+di, j+dj
            if 0 <= ni < n and 0 <= nj < n:
                neighbors.append(grid[ni][nj])
        return neighbors

    # BFS/dynamic programming approach
    # State: (i, j) -> minimum path list of length k starting from (i,j)
    # Use memoization with path length

    # At each step, we want to greedily pick the minimum
    # dp[step][(i,j)] = minimum path of length 'step' ending at (i,j)
    # But we need to track the full path for comparison

    # Better approach: at each position and step, store the minimum sequence
    # dp[i][j] = minimum path of length k starting at (i,j)

    # Use iterative approach: 
    # paths[i][j] = best path of remaining length starting at cell (i,j)

    # Build from length 1 to k
    # best[i][j] = best path of length remaining starting at (i,j)

    # Start with length 1: best path is just [grid[i][j]]
    current = {}
    for i in range(n):
        for j in range(n):
            current[(i,j)] = [grid[i][j]]

    for step in range(k-1):
        next_dp = {}
        for i in range(n):
